#!/usr/bin/env python3
import os, base64, re as _re

files = [
  ('app\\\\admin\\\\page.tsx', ''),
  ('app\\\\api\\\\admin\\\\orgs\\\\route.ts', ''),
  ('app\\\\api\\\\admin\\\\test-connection\\\\route.ts', ''),
  ('app\\\\api\\\\admin\\\\connect\\\\route.ts', ''),
  ('app\\\\api\\\\admin\\\\sync\\\\route.ts', ''),
]

for win_path, b64 in files:
    path = win_path.replace("\\\\", os.sep).replace("\\", os.sep)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    content = _re.sub(r"as const(\s+as const)+", "as const", content)
    with open(path, "wb") as f:
        f.write(content.encode("utf-8"))
    print(f"Written: {path}")
print("\nDone — git add . && git commit -m \"Admin panel + connection wizard\" && vercel --prod")
